#include <bits/stdc++.h>
using namespace std;
#define inf INT_MAX
void solve(int now_t) {
	int k;
	cin>>k;
	vector<int> a(k);
	for(int i=0; i<k; i++) {
		cin>>a[i];  // 读入音符音高
	}
	vector<int> dp(4,0);  //dp[j]表示当前音符选键 j 的最小违规次数，初始第一个音符选任意键,违规 0 次
	for(int i=1; i<k; i++) { //因为要 i-1 所以从 i=1 开始
		vector<int> new_dp(4,inf);//新状态初始化为无穷大
		if(a[i]==a[i-1]) {//前后音高相同
			//必须选相同琴键，直接继承
			for(int j=0; j<4; j++) {
				new_dp[j]=min(new_dp[j],dp[j]);
			}
		} else if(a[i]>a[i-1]) {//音高 i > 音高 i-1
			//枚举前一个音符的键 j 和当前音符的键 l
			for(int j=0; j<4; j++) {
				for(int l=0; l<4; l++) {
					if(l>j) {//合法：选了更高的键
						new_dp[l]=min(new_dp[l],dp[j]);
					} else {//非法：没能选更高键，违规 +1
						new_dp[l]=min(new_dp[l],dp[j]+1);
					}
				}
			}
		} else {//音高 i < 音高 i-1
			//枚举前一个音符的键 j 和当前音符的键 l
			for(int j=0; j<4; j++) {
				for(int l=0; l<4; l++) {
					if(j>l) {//合法：选了更低的键
						new_dp[l]=min(new_dp[l],dp[j]);
					} else {//非法：没能选更低键，违规 +1
						new_dp[l]=min(new_dp[l],dp[j]+1);
					}
				}
			}
		}
		dp=move(new_dp);//继承
	}
	int ans=inf;
	for(auto s:dp) {//取所有最终键的最小违规次数
		ans=min(ans,s);
	}
	cout<<"Case #"<<now_t<<": "<<ans<<"\n";
}
int t,now_t;//t 组数据,当前数据编号 now_t
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>t;
	while(t--) {
		now_t++;
		solve(now_t);
	}
	return 0;
}
